      console.error('PremblyPass widget is not loaded yet.');
      return;
    }

    const premblyPass = new window.PremblyPass({
      app_id: appId,
      x_api_key: xApiKey,
      environment: 'test',
    });

    premblyPass.launch({
      config_id: configId,
      user_ref: 'user_123',
      onSuccess: (data) => {
        console.log('Verification successful:', data);
        setVerified(true);
      },
      onClose: () => {
        console.log('Widget closed.');
      },
      onError: (error) => {
        console.error('Verification error:', error);
      },
    });
  };

  return (
    <div>
      <button id="verify-btn" onClick={handleVerify}>
        Verify Face Liveliness
      </button>
      {verified && (
        <div id="success-message">Verification successful</div>
      )}
    </div>
  );
}

